function ModelTreaFind:GetFindCost(type)
    if not self._costList then
        self._costList= {}
    end
    local cost = self._costList[type]
    if cost then
        return cost
    end
    local key = "callUseItem"
    if type == 2 then
        key = "callUseItemMore"
    end

    local para =self:GetPara(key)
    local itemList = LxDataHelper.ParseItem(para)
    if itemList then
        cost=itemList[1]
    end
    self._costList[type] = cost
    return cost
end

function ModelTreaFind:GetFindDiaCost(type)
    if not self._costDiaList then
        self._costDiaList= {}
    end
    local cost = self._costDiaList[type]
    if cost then
        return cost
    end
    local key = "callUseDiamond"
    if type == 2 then
        key = "callUseDiamondMore"
    end

    local para =self:GetPara(key)
    local itemList = LxDataHelper.ParseItem(para)
    if itemList then
        cost=itemList[1]
    end
    self._costDiaList[type] = cost
    return cost
end

