function ModelTreaFind:GetBoxRewardConfig()
    if not self._data then
        return
    end
    local cnt = self._data.boxRewardCount or 0
    cnt = cnt+1
    for k,v in pairs(GameTable.TreasureItemBoxRef) do
        if cnt>= v.numSmall then
            if v.numBig ~= -1 then
                if cnt< v.numBig then
                    return v
                end
            else
                return v
            end
        end
    end
end

function ModelTreaFind:FormatItemData(index)

    local itemData = {}
    local cfg = gModelTreaFind:GetPara("buyItemNum"..index)
    local itemList = LxDataHelper.ParseItem(cfg)
    if itemList then
        itemData.reward = itemList[1]
    end

    cfg = gModelTreaFind:GetPara("buyItemCost"..index)
    itemList = LxDataHelper.ParseItem(cfg)
    if itemList then
        itemData.price = itemList[1]
    end

    itemData.discount = gModelTreaFind:GetPara("buyItemDiscount"..index)
    itemData.type = index
    return itemData
end

function ModelTreaFind:GetGoodsList()

    local dataList =self._goodList
    if not dataList then
        dataList = {}
        self._goodList = dataList
    else
        return dataList
    end

    for k = 1,2 do
        local itemdata = self:FormatItemData(k)
        table.insert(dataList,itemdata)
    end

    return dataList
end

function ModelTreaFind:GetFreeFindCnt()
    if not self._data then
        return 0
    end
    local cnt = self._data.freeFindCount - self._data.findCountDay
    cnt = math.max(cnt,0)
    return cnt
end


function ModelTreaFind:ParseConfig()
    local typeCfg = {}
    local temp = self:GetPara("specialReward")
    local strs = string.split(temp,";")
    local maxTimes = 0
    for k,v in ipairs(strs) do
        local tempStr = string.split(v,"=")
        local times = math.floor(tonumber(tempStr[2]))
        local type = math.floor(tonumber(tempStr[3]))
        typeCfg[type] = times
        maxTimes = math.max(maxTimes,times)
    end

    self._typeCfg = typeCfg
    self._maxTimes = maxTimes
end

function ModelTreaFind:GetTreaIdByItemId(itemId)
    local treaId = -1
    local itemRef = gModelItem:GetRefByRefId(itemId)
    if not itemRef then
        return treaId
    end
    local type = itemRef.type
    if type == ModelItem.ITEM_TREASURE_ART then
        treaId = tonumber(itemRef.typeDate)
    end
    return treaId
end

