function ModelTreaFind:IsTreasureBoxEnough()
    local boxCfg = self:GetBoxRewardConfig()
    if boxCfg then
        local need = boxCfg.need
        local item = LxDataHelper.ParseItem_3(need)
        local own = gModelItem:GetNumByRefId(item.itemId)
        return own>=item.itemNum
    end
end

