function ModelTreaFind:ShowDiaTipWnd(type)
    local callNum = 1
    if type == 2 then
        callNum = self:GetPara("callNum")
    end

    local rewardFix = self:GetPara("rewardFix")
    local fixedRewardList = LxDataHelper.ParseItem(rewardFix)
    local itemdata  = fixedRewardList[1]
    itemdata.itemNum = callNum* itemdata.itemNum

    local str = gModelGeneral:GetCommonItemColorName(itemdata,'*')
    local diaCost = self:GetFindDiaCost(type)
    --local diaNum = diaCost.itemNum
    local costStr = string.format("%s%s",diaCost.itemNum,gModelGeneral:GetCommonItemName(diaCost))
    local para =
    {
        refId = 52404,
        para = {costStr,str,callNum},
        func = function()
            self:OnFindTreasureReq(type)
        end,
    }

    gModelGeneral:OpenUIOrdinTips(para)
end

function ModelTreaFind:ShowItemCostTipWnd(type)
    local callNum = 1
    if type == 2 then
        callNum = self:GetPara("callNum")
    end

    local rewardFix = self:GetPara("rewardFix")
    local fixedRewardList = LxDataHelper.ParseItem(rewardFix)
    local itemdata  = fixedRewardList[1]
    local itemNum = callNum* itemdata.itemNum
    local getItemStr = string.format("%s%s",itemNum,gModelGeneral:GetCommonItemName(itemdata))
    local cost = gModelTreaFind:GetFindCost(type)
    local costItemStr = string.format("%s%s",cost.itemNum,gModelGeneral:GetCommonItemName(cost))

    local para =
    {
        refId = 52405,
        para = {costItemStr,getItemStr,callNum},
        func = function()
            self:OnFindTreasureReq(type)
        end
    }

    gModelGeneral:OpenUIOrdinTips(para)
end

function ModelTreaFind:GetTodayCallNum()
    if not self._data then
        return 0
    end
    local findCnt = self._data.dayTotalCnt

    return findCnt
end

-- 总共抽取次数
function ModelTreaFind:GetFindTotal()
    if not self._data then return 0 end
    local findTotal = self._data.findTotal
    return findTotal
end

function ModelTreaFind:SendFindReq(type,wndName)
    if type == 1 then
        local freeCnt = self:GetFreeFindCnt()
        if freeCnt>0 then
            self:OnFindTreasureReq(type)
            return
        end
    end

    local callNum = 1
    if type == 2 then
        callNum = self:GetPara("callNum")
    end

    local totalCnt = self:GetTodayCallNum()
    local numLimit = gModelTreaFind:GetPara("dayExtractNumMax")
    if totalCnt + callNum > numLimit then
        local str = ccClientText(19680)
        GF.ShowMessage(str)
        return
    end


    local cost = self:GetFindCost(type)
    local itemId = cost.itemId
    local own = gModelItem:GetNumByRefId(itemId)
    if own>=cost.itemNum then
        self:ShowItemCostTipWnd(type)
        return
    end

    local diaCost = self:GetFindDiaCost(type)
    own = gModelItem:GetNumByRefId(diaCost.itemId)
    if own >= diaCost.itemNum then
        self:ShowDiaTipWnd(type)
        return
    end

    gModelGeneral:OpenGetWayWnd({itemId = diaCost.itemId,srcWnd = wndName})
end

return ModelTreaFind